mapper.select:
SELECT wo.id, wo.work_order_no AS workOrderNo, i.item_code AS itemCode, i.item_name AS itemName, wo.plan_qty AS planQty, wo.plan_date AS planDate, wo.status, wo.line, wo.remark, wo.confirm_yn AS confirmYn, wo.created_by AS createdBy, wo.created_at AS createdAt, wo.updated_by AS updatedBy, wo.updated_at AS updatedAt FROM mes_work_order wo LEFT JOIN mes_item i ON wo.item_id = i.id WHERE wo.use_yn = 'Y'
AND wo.plan_date >= CAST(#{startDate} AS date)
AND wo.plan_date <= CAST(#{endDate} AS date)
AND wo.status = #{status}
AND wo.confirm_yn = #{confirmYn}
ORDER BY wo.plan_date DESC, wo.id DESC
